import { useState } from "react";
import API from "../services/api";
import { supabase } from "../services/supabaseClient";

export default function Upload({ user, setUser }) {
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [summary, setSummary] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [loading, setLoading] = useState(false);

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [asking, setAsking] = useState(false);

  const [docId, setDocId] = useState(null);
  const [userId, setUserId] = useState(null);

  const [papers, setPapers] = useState([]);
  const [loadingRec, setLoadingRec] = useState(false);

  // 🔐 Auth Header
  const getAuthHeader = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session ? { Authorization: `Bearer ${session.access_token}` } : {};
  };

  // 📄 Upload
  const handleUpload = async () => {
    if (!file) return alert("Select a file");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const formData = new FormData();
      formData.append("file", file);

      const res = await API.post("/upload", formData, {
        headers: {
          ...authHeader,
          "Content-Type": "multipart/form-data"
        }
      });

      setText(res.data.preview);
      setDocId(res.data.doc_id);
      setUserId(res.data.user_id);

      setAnswer("");
      setQuestion("");
      setSummary("");
      setShowSummary(false);
      setPapers([]);

    } catch (err) {
      console.error(err);
      alert("Upload failed ❌");
    } finally {
      setLoading(false);
    }
  };

  // 💬 Q&A
  const askQuestion = async () => {
    if (!question || !docId) return alert("Upload + enter question");

    try {
      setAsking(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/ask", {
        question,
        doc_id: docId,
        userId
      }, { headers: authHeader });

      setAnswer(res.data.answer);

    } catch (err) {
      console.error(err);
    } finally {
      setAsking(false);
    }
  };

  // 🧠 Summary
  const handleGenerateSummary = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/summarize", { text }, { headers: authHeader });

      setSummary(res.data.summary);
      setShowSummary(true);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // 🔍 Recommend
  const handleRecommend = async () => {
    try {
      setLoadingRec(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/recommend", {
        query: text
      }, { headers: authHeader });

      setPapers(res.data.recommendations || []);

    } catch (err) {
      console.error(err);
    } finally {
      setLoadingRec(false);
    }
  };

  return (
    <div className="space-y-8">
      {/* Upload Card */}
      <div className="bg-white/80 backdrop-blur-sm shadow-xl rounded-3xl p-8 border border-white/50 hover:shadow-2xl transition-all duration-500 hover-lift animate-fade-in-up">
        <h2 className="text-2xl font-bold mb-6 bg-gradient-to-r from-gray-800 to-slate-800 bg-clip-text text-transparent">
          📄 Upload Research Paper
        </h2>

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <input
            type="file"
            accept=".pdf"
            onChange={(e) => setFile(e.target.files[0])}
            className="file:mr-4 file:rounded-xl file:border-0 file:bg-gradient-to-r file:from-blue-500 file:to-indigo-600 file:text-white file:py-3 file:px-6 file:font-semibold file:cursor-pointer file:transition-all file:hover:from-blue-600 file:hover:to-indigo-700 w-full md:w-1/2 p-4 border-2 border-dashed border-gray-300 rounded-2xl hover:border-blue-400 transition-all duration-300 focus:border-blue-500"
          />

          <button
            onClick={handleUpload}
            disabled={loading}
            className="btn bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 shadow-xl hover:shadow-2xl w-full md:w-auto px-8 py-4 text-lg font-bold rounded-2xl"
          >
            {loading ? "⏳ Processing..." : "🚀 Upload & Analyze"}
          </button>
        </div>
      </div>

      {/* Preview */}
      {text && (
        <div className="bg-gradient-to-r from-gray-50 to-blue-50 p-8 rounded-3xl shadow-lg border border-blue-100 animate-fade-in-up hover-lift hover:shadow-xl">
          <h3 className="text-xl font-bold mb-4 text-gray-800">📖 Extracted Text Preview</h3>
          <div className="max-h-48 overflow-y-auto p-4 bg-white rounded-2xl border">
            <p className="text-sm leading-relaxed">
              {text.slice(0, 1000)}...
            </p>
          </div>
        </div>
      )}

      {/* Action Buttons */}
      {text && (
        <div className="flex flex-col sm:flex-row gap-4 animate-fade-in-up" style={{animationDelay: '0.2s'}}>
          <button onClick={handleGenerateSummary} className="btn bg-gradient-to-r from-purple-500 to-pink-600 hover:from-purple-600 hover:to-pink-700 shadow-xl flex-1 py-4 text-lg" disabled={loading}>
            🧠 Generate Summary
          </button>
          <button onClick={handleRecommend} className="btn bg-gradient-to-r from-orange-500 to-red-500 hover:from-orange-600 hover:to-red-600 shadow-xl flex-1 py-4 text-lg" disabled={loadingRec}>
            {loadingRec ? "🔍 Finding similar..." : "🔍 AI Recommendations"}
          </button>
        </div>
      )}

      {/* Summary */}
      {showSummary && (
        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 p-8 rounded-3xl shadow-xl border border-blue-200 animate-fade-in-up hover-lift">
          <h3 className="text-2xl font-bold mb-6 text-blue-900 flex items-center gap-3">
            📝 AI Summary
            <span className="text-sm bg-blue-200 px-3 py-1 rounded-full font-medium">Ready</span>
          </h3>
          <div className="prose max-w-none leading-relaxed">
            <p>{summary}</p>
          </div>
        </div>
      )}

      {/* Q&A */}
      {text && (
        <div className="animate-fade-in-up hover-lift">
          <h3 className="text-2xl font-bold mb-6 bg-gradient-to-r from-green-600 to-emerald-600 bg-clip-text text-transparent flex items-center gap-3">
            💬 Ask Anything
          </h3>

          <div className="flex gap-4">
            <input
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              className="flex-1 p-5 rounded-2xl border-2 border-gray-200 focus:border-emerald-400 focus:outline-none focus:ring-4 ring-emerald-200/50 transition-all duration-300 shadow-inner hover:shadow-md"
              placeholder="Ask about the paper, methods, findings..."
            />
            <button onClick={askQuestion} className="btn bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 shadow-xl px-10 py-5 text-lg" disabled={asking || !docId}>
              {asking ? "🤔 Thinking..." : "Send"}
            </button>
          </div>

          {answer && (
            <div className="mt-8 bg-gradient-to-r from-emerald-50 to-green-50 p-8 rounded-3xl shadow-lg border border-emerald-200 animate-fade-in-up">
              <h4 className="text-xl font-bold mb-4 text-emerald-900 flex items-center gap-3">
                💡 AI Answer
              </h4>
              <div className="prose max-w-none">
                <p>{answer}</p>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Recommendations */}
      {papers.length > 0 && (
        <div className="animate-fade-in-up hover-lift">
          <h3 className="text-2xl font-bold mb-6 bg-gradient-to-r from-purple-600 to-violet-600 bg-clip-text text-transparent">
            📚 Related Papers
          </h3>
          <div className="grid md:grid-cols-2 gap-4">
            {papers.map((title, i) => (
              <div key={i} className="bg-gradient-to-r from-white to-purple-50 p-6 rounded-2xl shadow-md hover:shadow-xl hover-lift border border-purple-100 hover:border-purple-200 transition-all duration-300">
                <span className="inline-block w-2 h-2 bg-purple-500 rounded-full mr-3"></span>
                <span className="text-gray-800 font-medium leading-relaxed">{title}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
